import { api, downloadBlob } from './api.js';
import { cardWrap, fr, evBar, pillSt, tag, spinner, emptyState } from './helpers.js';
import { FALLBACK_CONDITIONS, FALLBACK_MODALITIES } from './constants.js';
import { renderLiveEvidencePanel } from './live-evidence.js';
import { EVIDENCE_SUMMARY, EVIDENCE_TOTAL_PAPERS, CONDITION_EVIDENCE, getConditionEvidence, getTopConditionsByPaperCount } from './evidence-dataset.js';
import { PROTOCOL_LIBRARY, CONDITIONS as PROTO_CONDITIONS, DEVICES as PROTO_DEVICES, getProtocolsByCondition } from './protocols-data.js';
import { renderBrainMap10_20, SITES_10_20 } from './brain-map-svg.js';
import { getEvidenceUiStats } from './evidence-ui-live.js';

function _kEsc(v) {
  if (v == null) return '';
  return String(v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#x27;');
}

// ── Evidence Library ──────────────────────────────────────────────────────────
export async function pgEvidence(setTopbar) {
  setTopbar('Evidence Library', '');
  const el = document.getElementById('content');
  el.innerHTML = spinner();

  let items = [];
  try {
    const res = await api.listEvidence();
    items = res?.items || [];
  } catch (e) {
    // Don't abort — the live-evidence panel still works without the curated library.
    items = [];
  }

  const liveEvidence = await getEvidenceUiStats({
    fallbackSummary: EVIDENCE_SUMMARY,
    fallbackConditionCount: CONDITION_EVIDENCE.length,
  });
  const _tp = liveEvidence.totalPapers;
  const _tt = liveEvidence.totalTrials;
  const _tm = liveEvidence.totalMetaAnalyses;
  const _tc = liveEvidence.totalConditions;

  // Build modality options from data
  const modalitySet = new Set(items.map(e => e.modality).filter(Boolean));

  el.innerHTML = `
  <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:10px;margin-bottom:18px">
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,10px);padding:14px 16px;text-align:center">
      <div style="font-size:20px;font-weight:800;color:var(--teal);font-family:var(--font-display)">${(_tp/1000).toFixed(0)}K</div>
      <div style="font-size:10.5px;color:var(--text-tertiary)">Curated papers</div>
    </div>
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,10px);padding:14px 16px;text-align:center">
      <div style="font-size:20px;font-weight:800;color:var(--blue);font-family:var(--font-display)">${_tt.toLocaleString()}</div>
      <div style="font-size:10.5px;color:var(--text-tertiary)">Clinical trials</div>
    </div>
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,10px);padding:14px 16px;text-align:center">
      <div style="font-size:20px;font-weight:800;color:var(--violet);font-family:var(--font-display)">${_tm.toLocaleString()}</div>
      <div style="font-size:10.5px;color:var(--text-tertiary)">Meta-analyses</div>
    </div>
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,10px);padding:14px 16px;text-align:center">
      <div style="font-size:20px;font-weight:800;color:var(--rose);font-family:var(--font-display)">${_tc}</div>
      <div style="font-size:10.5px;color:var(--text-tertiary)">Conditions covered</div>
    </div>
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,10px);padding:14px 16px;text-align:center">
      <div style="font-size:20px;font-weight:800;color:var(--amber);font-family:var(--font-display)">${PROTOCOL_LIBRARY?.length || 0}</div>
      <div style="font-size:10.5px;color:var(--text-tertiary)">Protocols</div>
    </div>
  </div>
  <div id="live-evidence-host"></div>
  <div style="display:flex;gap:8px;margin-bottom:16px;flex-wrap:wrap">
    <input class="form-control" id="ev-search" placeholder="Search conditions, modalities, summaries…" style="flex:1;min-width:200px" oninput="window.filterEvidence()">
    <select class="form-control" id="ev-level" style="width:auto" onchange="window.filterEvidence()">
      <option value="">All Evidence Levels</option>
      <option value="A" style="color:#00d4bc;background:#0a1628">Grade A — Strong RCT</option>
      <option value="B" style="color:#4a9eff;background:#0a1628">Grade B — Moderate</option>
      <option value="C" style="color:#f59e0b;background:#0a1628">Grade C — Emerging</option>
      <option value="D" style="color:#f87171;background:#0a1628">Grade D — Limited</option>
    </select>
    <select class="form-control" id="ev-modality" style="width:auto" onchange="window.filterEvidence()">
      <option value="">All Modalities</option>
      ${[...modalitySet].sort().map(m => `<option value="${m}">${m}</option>`).join('')}
    </select>
  </div>
  <div id="ev-count" style="font-size:11.5px;color:var(--text-tertiary);margin-bottom:10px">${items.length} evidence records · ${(_tp/1000).toFixed(0)}K papers indexed across ${_tc} conditions</div>
  <div id="ev-body">
    ${items.length === 0
      ? emptyState('◈', `No evidence records loaded. Start the backend to load clinical data. ${_tp.toLocaleString()} papers are available in the current evidence corpus.`)
      : renderEvidenceTable(items)}
  </div>`;

  // Mount the live-evidence panel (PubMed / OpenAlex / CT.gov / FDA via our
  // evidence pipeline). Non-fatal: if the evidence DB isn't ingested yet,
  // the panel shows its own clear "not ready" message and the rest of the
  // Evidence Library page continues to work.
  renderLiveEvidencePanel(document.getElementById('live-evidence-host'));

  window._evidenceData = items;

  window.filterEvidence = function() {
    const q   = document.getElementById('ev-search')?.value.toLowerCase() || '';
    const lvl = document.getElementById('ev-level')?.value || '';
    const mod = document.getElementById('ev-modality')?.value || '';
    const filtered = (window._evidenceData || []).filter(e => {
      const matchQ = !q || (e.title || '').toLowerCase().includes(q)
        || (e.condition || '').toLowerCase().includes(q)
        || (e.modality || '').toLowerCase().includes(q)
        || (e.summary || '').toLowerCase().includes(q)
        || (e.symptom_cluster || '').toLowerCase().includes(q);
      const matchL = !lvl || (e.evidence_level || '').includes(lvl);
      const matchM = !mod || (e.modality || '') === mod;
      return matchQ && matchL && matchM;
    });
    const body  = document.getElementById('ev-body');
    const count = document.getElementById('ev-count');
    if (count) count.textContent = `${filtered.length} of ${(window._evidenceData||[]).length} evidence records`;
    if (body) body.innerHTML = filtered.length === 0 ? emptyState('◈', 'No records match filter.') : renderEvidenceTable(filtered);
  };
}

function renderEvidenceTable(items) {
  return `<div class="g3">
    ${items.map((e, idx) => {
      const evGrade = (e.evidence_level || '?').charAt(0);
      const gradeMap = { A:{ color:'#16a34a', bg:'#16a34a18', label:'Strong RCT' }, B:{ color:'#3b82f6', bg:'#3b82f618', label:'Moderate' }, C:{ color:'#f59e0b', bg:'#f59e0b18', label:'Emerging' }, D:{ color:'#ef4444', bg:'#ef444418', label:'Limited' } };
      const g = gradeMap[evGrade] || { color:'#64748b', bg:'#64748b18', label:'Ungraded' };

      // Mini evidence strength gauge SVG
      const barCount = evGrade === 'A' ? 4 : evGrade === 'B' ? 3 : evGrade === 'C' ? 2 : 1;
      const gaugeSvg = `<svg viewBox="0 0 100 44" width="100" height="44" style="display:block">
        <defs><linearGradient id="evg-${idx}" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="${g.color}" stop-opacity="0.12"/>
          <stop offset="100%" stop-color="${g.color}" stop-opacity="0"/>
        </linearGradient></defs>
        <rect width="100" height="44" fill="url(#evg-${idx})" rx="6"/>
        ${[0,1,2,3].map(i => {
          const bx = 12 + i * 20; const bh = 8 + i * 7; const by = 38 - bh;
          const active = i < barCount;
          return `<rect x="${bx}" y="${by}" width="14" height="${bh}" rx="2" fill="${active ? g.color : g.color + '20'}" opacity="${active ? 0.8 : 0.3}"/>`;
        }).join('')}
        <text x="50" y="10" font-size="7" fill="${g.color}" text-anchor="middle" opacity="0.7" font-weight="600">Grade ${evGrade}</text>
      </svg>`;

      const teaser = (e.summary || '').slice(0, 100) + ((e.summary || '').length > 100 ? '...' : '');

      return `<div class="card" style="margin-bottom:0;cursor:pointer;transition:border-color var(--transition),transform .15s,box-shadow .15s"
        onmouseover="this.style.borderColor='${g.color}60';this.style.transform='translateY(-2px)';this.style.boxShadow='0 8px 24px ${g.color}15'"
        onmouseout="this.style.borderColor='var(--border)';this.style.transform='';this.style.boxShadow=''"
        onclick="window._openEvidenceDetail(${idx})">
        <div style="padding:14px 16px">
          <div style="display:flex;gap:14px;align-items:flex-start">
            <!-- Evidence Gauge -->
            <div style="flex-shrink:0;width:110px;border-radius:10px;background:${g.bg};border:1px solid ${g.color}20;padding:8px 5px 6px;text-align:center">
              ${gaugeSvg}
              <div style="font-size:9px;color:${g.color};font-weight:600;margin-top:3px">${g.label}</div>
            </div>
            <!-- Content -->
            <div style="min-width:0;flex:1">
              <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin-bottom:4px">
                <span style="font-size:10px;font-weight:700;padding:2px 7px;border-radius:999px;background:${g.bg};color:${g.color}">EV-${evGrade}</span>
                ${e.modality ? `<span style="font-size:10px;padding:2px 7px;border-radius:999px;background:rgba(255,255,255,0.04);border:1px solid var(--border);color:var(--text-tertiary)">${e.modality}</span>` : ''}
              </div>
              <div style="font-family:var(--font-display);font-size:13px;font-weight:600;color:var(--text-primary);margin-bottom:2px;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden">${e.title || e.condition || '—'}</div>
              <div style="font-size:10.5px;color:var(--text-tertiary);margin-bottom:6px">${e.condition || ''}${e.symptom_cluster ? ' &middot; ' + e.symptom_cluster : ''}</div>
              <div style="font-size:11px;color:var(--text-secondary);line-height:1.5">${teaser}</div>
            </div>
            <!-- Arrow -->
            <div style="color:${g.color};opacity:0.4;font-size:18px;padding-top:14px">&rarr;</div>
          </div>
        </div>
      </div>`;
    }).join('')}
  </div>`;
}

// Evidence detail modal
function _openEvidenceModal(evidence) {
  const old = document.getElementById('ds-evidence-modal');
  if (old) old.remove();

  const evGrade = (evidence.evidence_level || '?').charAt(0);
  const gradeMap = { A:{ color:'#16a34a', label:'Grade A — Strong RCT / Meta-analysis' }, B:{ color:'#3b82f6', label:'Grade B — Moderate RCT evidence' }, C:{ color:'#f59e0b', label:'Grade C — Emerging / Observational' }, D:{ color:'#ef4444', label:'Grade D — Limited / Case Reports' } };
  const g = gradeMap[evGrade] || { color:'#64748b', label:'Ungraded' };

  // Find related protocols from protocol library
  const relatedProtos = PROTOCOL_LIBRARY.filter(p => {
    const cond = (evidence.condition || '').toLowerCase();
    const mod = (evidence.modality || '').toLowerCase();
    return (p.conditionId || '').replace(/-/g, ' ').includes(cond) || (p.name || '').toLowerCase().includes(mod);
  }).slice(0, 8);

  // Get condition evidence data
  const condEvidence = evidence.condition ? getConditionEvidence(
    (evidence.condition || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '')
  ) : null;

  const overlay = document.createElement('div');
  overlay.id = 'ds-evidence-modal';
  overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.55);display:flex;align-items:center;justify-content:center;padding:24px;backdrop-filter:blur(4px)';

  overlay.innerHTML = `
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,12px);max-width:780px;width:100%;max-height:90vh;overflow-y:auto;box-shadow:0 24px 80px rgba(0,0,0,0.4)" onclick="event.stopPropagation()">
      <!-- Header -->
      <div style="position:sticky;top:0;z-index:1;background:var(--bg-card);border-bottom:1px solid var(--border);padding:20px 24px;display:flex;align-items:flex-start;gap:14px">
        <div style="flex-shrink:0;width:44px;height:44px;border-radius:10px;background:${g.color}18;border:1px solid ${g.color}30;display:flex;align-items:center;justify-content:center">
          <span style="font-size:16px;font-weight:800;color:${g.color}">${evGrade}</span>
        </div>
        <div style="flex:1;min-width:0">
          <div style="font-family:var(--font-display);font-size:16px;font-weight:700;color:var(--text-primary);line-height:1.35">${_kEsc(evidence.title || evidence.condition) || '—'}</div>
          <div style="display:flex;gap:6px;align-items:center;margin-top:5px;flex-wrap:wrap">
            <span style="font-size:10px;padding:2px 8px;border-radius:999px;background:${g.color}18;color:${g.color};font-weight:600">${g.label}</span>
            ${evidence.modality ? `<span style="font-size:10px;padding:2px 8px;border-radius:999px;background:rgba(255,255,255,0.04);border:1px solid var(--border);color:var(--text-tertiary)">${_kEsc(evidence.modality)}</span>` : ''}
          </div>
        </div>
        <button onclick="document.getElementById('ds-evidence-modal')?.remove();document.body.style.overflow=''" style="background:none;border:none;color:var(--text-tertiary);cursor:pointer;font-size:20px;padding:4px 8px">&times;</button>
      </div>

      <div style="padding:24px">
        <!-- Key Info Grid -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px;margin-bottom:24px">
          ${[
            ['Condition', evidence.condition, 'var(--teal)'],
            ['Modality', evidence.modality, 'var(--blue)'],
            ['Symptom Cluster', evidence.symptom_cluster, 'var(--violet)'],
            ['Setting', evidence.setting, 'var(--amber)'],
            ['Regulatory', evidence.regulatory_status, evidence.regulatory_status?.toLowerCase().includes('fda') ? 'var(--green)' : 'var(--text-tertiary)'],
          ].filter(([,v]) => v).map(([k, v, color]) => `
            <div style="background:rgba(255,255,255,0.02);border:1px solid var(--border);border-radius:10px;padding:12px">
              <div style="font-size:9.5px;text-transform:uppercase;letter-spacing:.6px;color:var(--text-tertiary);margin-bottom:4px">${k}</div>
              <div style="font-size:13px;font-weight:600;color:${color}">${v}</div>
            </div>`).join('')}
        </div>

        ${condEvidence ? `<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:24px">
          <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:10px;padding:12px;text-align:center">
            <div style="font-size:22px;font-weight:800;color:var(--teal)">${condEvidence.paperCount?.toLocaleString() || '—'}</div>
            <div style="font-size:9.5px;color:var(--text-tertiary)">Research Papers</div>
          </div>
          <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:10px;padding:12px;text-align:center">
            <div style="font-size:22px;font-weight:800;color:var(--blue)">${condEvidence.trialCount?.toLocaleString() || '—'}</div>
            <div style="font-size:9.5px;color:var(--text-tertiary)">Clinical Trials</div>
          </div>
          <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:10px;padding:12px;text-align:center">
            <div style="font-size:22px;font-weight:800;color:var(--violet)">${condEvidence.metaAnalysisCount?.toLocaleString() || '—'}</div>
            <div style="font-size:9.5px;color:var(--text-tertiary)">Meta-Analyses</div>
          </div>
        </div>` : ''}

        <!-- Summary -->
        ${evidence.summary ? `<div style="margin-bottom:20px">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--text-tertiary);font-weight:600;margin-bottom:8px">Study Summary</div>
          <div style="font-size:12.5px;color:var(--text-secondary);line-height:1.65;padding:14px;background:rgba(0,0,0,0.15);border-radius:10px;border:1px solid var(--border)">${evidence.summary}</div>
        </div>` : ''}

        <!-- Related Protocols -->
        ${relatedProtos.length ? `<div style="margin-bottom:20px">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--text-tertiary);font-weight:600;margin-bottom:8px">Related Protocols (${relatedProtos.length})</div>
          <div style="display:flex;flex-direction:column;gap:6px;max-height:220px;overflow-y:auto">
            ${relatedProtos.map(p => {
              const gc = {'A':'var(--green)','B':'var(--blue)','C':'var(--amber)','D':'var(--rose)'}[p.evidenceGrade] || 'var(--text-tertiary)';
              return `<div style="display:flex;align-items:center;gap:10px;padding:8px 12px;border-radius:8px;background:rgba(255,255,255,0.02);border:1px solid var(--border)">
                <span style="font-size:10px;font-weight:700;padding:2px 6px;border-radius:4px;background:${gc}18;color:${gc}">${p.evidenceGrade || '?'}</span>
                <div style="flex:1;min-width:0">
                  <div style="font-size:11.5px;font-weight:600;color:var(--text-primary);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${p.name}</div>
                  <div style="font-size:10px;color:var(--text-tertiary)">${p.target || ''} &middot; ${p.subtype || ''}</div>
                </div>
              </div>`;
            }).join('')}
          </div>
        </div>` : ''}

        <!-- Reference / DOI -->
        ${evidence.reference || evidence.doi ? `<div style="margin-bottom:16px;padding:12px;background:rgba(255,255,255,0.02);border-radius:8px;border:1px solid var(--border)">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--text-tertiary);font-weight:600;margin-bottom:6px">Reference</div>
          ${evidence.reference ? `<div style="font-size:12px;color:var(--text-secondary);line-height:1.5;margin-bottom:4px">${evidence.reference}</div>` : ''}
          ${evidence.doi ? `<div style="font-size:11px;color:var(--text-tertiary)">DOI: <span style="font-family:var(--font-mono)">${evidence.doi}</span></div>` : ''}
        </div>` : ''}

        <!-- Action buttons -->
        <div style="display:flex;gap:8px;flex-wrap:wrap">
          <button class="btn btn-sm" onclick="document.getElementById('ds-evidence-modal')?.remove();document.body.style.overflow='';window._nav('protocols-registry')">Find Protocols &rarr;</button>
          ${evidence.modality ? `<button class="btn btn-sm" onclick="document.getElementById('ds-evidence-modal')?.remove();document.body.style.overflow='';window._nav('devices')">Device Registry &rarr;</button>` : ''}
        </div>
      </div>
    </div>`;

  overlay.addEventListener('click', (e) => { if (e.target === overlay) { overlay.remove(); document.body.style.overflow = ''; } });
  document.body.style.overflow = 'hidden';
  document.body.appendChild(overlay);
  const esc = (e) => { if (e.key === 'Escape') { overlay.remove(); document.body.style.overflow = ''; document.removeEventListener('keydown', esc); } };
  document.addEventListener('keydown', esc);
}

window._openEvidenceDetail = function(idx) {
  const evidence = (window._evidenceData || [])[idx];
  if (!evidence) return;
  _openEvidenceModal(evidence);
};

// ── Device Registry ───────────────────────────────────────────────────────────
export async function pgDevices(setTopbar) {
  setTopbar('Device Registry', `<button class="btn btn-ghost btn-sm">Export</button>`);
  const el = document.getElementById('content');
  el.innerHTML = spinner();

  let items = [];
  try {
    const res = await api.listDevices();
    items = res?.items || [];
  } catch (e) {
    // Fallback to local curated device data instead of showing error
    items = [];
  }

  // If API returned nothing, build device entries from local PROTO_DEVICES
  if (!items.length && PROTO_DEVICES?.length) {
    items = PROTO_DEVICES.map(d => ({
      id: d.id,
      name: d.label || d.id,
      modality: d.label || d.id,
      manufacturer: '',
      summary: 'Curated neuromodulation device from local evidence library',
      regulatory_status: '',
    }));
  }

  // Build per-device evidence stats from indexed corpus
  const _devEvStats = {};
  for (const d of PROTO_DEVICES || []) {
    const protos = PROTOCOL_LIBRARY.filter(p => p.device === d.id);
    const condIds = new Set(protos.map(p => p.conditionId));
    let papers = 0;
    for (const cid of condIds) {
      const ev = getConditionEvidence(cid);
      if (ev) papers += ev.paperCount;
    }
    _devEvStats[d.id] = { protocols: protos.length, conditions: condIds.size, papers, gradeA: protos.filter(p => p.evidenceGrade === 'A').length };
    // Also map by label for API devices
    _devEvStats[d.label?.toLowerCase()] = _devEvStats[d.id];
  }

  // Evidence KPI banner
  const _totalProtos = PROTOCOL_LIBRARY?.length || 0;
  const _totalPapers = EVIDENCE_SUMMARY?.totalPapers || EVIDENCE_TOTAL_PAPERS;
  const _totalTrials = EVIDENCE_SUMMARY?.totalTrials || 0;

  el.innerHTML = `
  <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:10px;margin-bottom:18px">
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,10px);padding:14px 16px;text-align:center">
      <div style="font-size:20px;font-weight:800;color:var(--teal);font-family:var(--font-display)">${items.length}</div>
      <div style="font-size:10.5px;color:var(--text-tertiary)">Devices</div>
    </div>
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,10px);padding:14px 16px;text-align:center">
      <div style="font-size:20px;font-weight:800;color:var(--blue);font-family:var(--font-display)">${_totalProtos}</div>
      <div style="font-size:10.5px;color:var(--text-tertiary)">Protocols</div>
    </div>
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,10px);padding:14px 16px;text-align:center">
      <div style="font-size:20px;font-weight:800;color:var(--violet);font-family:var(--font-display)">${(_totalPapers / 1000).toFixed(0)}K</div>
      <div style="font-size:10.5px;color:var(--text-tertiary)">Research papers</div>
    </div>
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,10px);padding:14px 16px;text-align:center">
      <div style="font-size:20px;font-weight:800;color:var(--rose);font-family:var(--font-display)">${_totalTrials.toLocaleString()}</div>
      <div style="font-size:10.5px;color:var(--text-tertiary)">Clinical trials</div>
    </div>
  </div>
  <div style="display:flex;gap:8px;margin-bottom:16px;flex-wrap:wrap">
    <input class="form-control" id="dev-search" placeholder="Search devices, manufacturers…" style="flex:1" oninput="window.filterDevices()">
    <select class="form-control" id="dev-modality" style="width:auto" onchange="window.filterDevices()">
      <option value="">All Modalities</option>
      <option>tDCS</option><option>TMS</option><option>taVNS</option><option>CES</option><option>Neurofeedback</option><option>TPS</option>
    </select>
  </div>
  <div id="dev-body">
    ${items.length === 0
      ? emptyState('◇', 'No devices loaded. Start the backend to load registry data.')
      : renderDeviceGrid(items, _devEvStats)}
  </div>`;

  window._devicesData = items;
  window._devEvStats  = _devEvStats;

  window._openDeviceDetail = function(idx) {
    const device = (window._devicesData || [])[idx];
    if (!device) return;
    const protoDevice = _findProtoDevice(device);
    const _did = (device.id || '').toLowerCase();
    const _dmod = (device.modality || device.name || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
    const de = (window._devEvStats || {})[_did] || (window._devEvStats || {})[_dmod] || {};
    _openDeviceModal(device, de, protoDevice);
  };

  window.filterDevices = function() {
    const q = document.getElementById('dev-search').value.toLowerCase();
    const mod = document.getElementById('dev-modality').value;
    const filtered = (window._devicesData || []).filter(d => {
      const matchQ = !q || (d.name || '').toLowerCase().includes(q) || (d.manufacturer || '').toLowerCase().includes(q);
      const matchM = !mod || (d.modality || '').toLowerCase().includes(mod.toLowerCase());
      return matchQ && matchM;
    });
    const body = document.getElementById('dev-body');
    if (body) body.innerHTML = filtered.length === 0 ? emptyState('◇', 'No devices match filter.') : renderDeviceGrid(filtered, window._devEvStats || {});
  };
}

// ── Device type colour + SVG illustrations ──────────────────────────────────
const _DEV_COLORS = {
  tms:'#8b5cf6', tdcs:'#3b82f6', tacs:'#0ea5e9', ces:'#f59e0b', tavns:'#14b8a6',
  tps:'#ec4899', pbm:'#f97316', pemf:'#6366f1', nf:'#10b981', tus:'#06b6d4',
  dbs:'#e11d48', vns:'#8b5cf6', other:'#64748b',
};

function _miniDeviceSvg(deviceId) {
  const c = _DEV_COLORS[deviceId] || '#64748b';
  const w = 110, h = 50;
  // Each device type gets a distinctive waveform/icon SVG
  let path = '';
  switch (deviceId) {
    case 'tms': // magnetic pulse bursts
      path = `<circle cx="55" cy="22" r="14" fill="none" stroke="${c}" stroke-width="1.5" opacity="0.5"/>
        <circle cx="55" cy="22" r="8" fill="none" stroke="${c}" stroke-width="2"/>
        <line x1="18" y1="40" x2="92" y2="40" stroke="${c}" stroke-width="0.4" stroke-dasharray="2,3" opacity="0.3"/>
        ${[25,40,55,70,85].map((x,i) => {const a = [18,28,22,26,14][i]; return `<line x1="${x}" y1="40" x2="${x}" y2="${40-a}" stroke="${c}" stroke-width="2" stroke-linecap="round" opacity="0.7"/>`; }).join('')}`;
      break;
    case 'tdcs': // steady DC current flow
      path = `<rect x="15" y="14" width="18" height="24" rx="3" fill="${c}" opacity="0.15" stroke="${c}" stroke-width="1"/>
        <rect x="77" y="14" width="18" height="24" rx="3" fill="${c}" opacity="0.15" stroke="${c}" stroke-width="1"/>
        <text x="24" y="30" font-size="10" fill="${c}" text-anchor="middle" font-weight="700">+</text>
        <text x="86" y="30" font-size="10" fill="${c}" text-anchor="middle" font-weight="700">&minus;</text>
        <path d="M36 26 Q55 18 74 26" fill="none" stroke="${c}" stroke-width="1.5" stroke-dasharray="4,2" opacity="0.6"/>
        <polygon points="72,24 76,26 72,28" fill="${c}" opacity="0.6"/>`;
      break;
    case 'tacs': // alternating sine wave
      { const pts = []; for (let i=0;i<=50;i++){const t=i/50; const x=10+t*90; const y=25-Math.sin(t*4*Math.PI)*14; pts.push(`${x.toFixed(1)},${y.toFixed(1)}`);} 
        path = `<polyline points="${pts.join(' ')}" fill="none" stroke="${c}" stroke-width="1.8" stroke-linecap="round" opacity="0.8"/>
        <line x1="10" y1="25" x2="100" y2="25" stroke="${c}" stroke-width="0.3" stroke-dasharray="2,3" opacity="0.3"/>`; }
      break;
    case 'ces': // dual ear clips with current
      path = `<ellipse cx="28" cy="25" rx="10" ry="14" fill="none" stroke="${c}" stroke-width="1.5" opacity="0.6"/>
        <ellipse cx="82" cy="25" rx="10" ry="14" fill="none" stroke="${c}" stroke-width="1.5" opacity="0.6"/>
        <circle cx="28" cy="25" r="3" fill="${c}" opacity="0.4"/>
        <circle cx="82" cy="25" r="3" fill="${c}" opacity="0.4"/>
        <path d="M38 25 Q55 18 72 25" fill="none" stroke="${c}" stroke-width="1.2" stroke-dasharray="3,2" opacity="0.5"/>`;
      break;
    case 'tavns': // ear with stimulation point
      path = `<path d="M45 8 Q30 18 32 30 Q34 42 45 44 Q56 42 58 30 Q60 18 45 8" fill="none" stroke="${c}" stroke-width="1.5" opacity="0.6"/>
        <circle cx="42" cy="28" r="4" fill="${c}" opacity="0.5"/>
        ${[0,1,2].map(i => `<circle cx="42" cy="28" r="${8+i*5}" fill="none" stroke="${c}" stroke-width="0.8" opacity="${0.3-i*0.08}"/>`).join('')}
        <line x1="62" y1="28" x2="95" y2="28" stroke="${c}" stroke-width="1" stroke-dasharray="3,2" opacity="0.4"/>`;
      break;
    case 'nf': // EEG feedback loop
      { const pts = []; for (let i=0;i<=40;i++){const t=i/40; const x=10+t*90; const y=20-Math.sin(t*8*Math.PI)*8*Math.exp(-t*1.5); pts.push(`${x.toFixed(1)},${y.toFixed(1)}`);} 
        path = `<polyline points="${pts.join(' ')}" fill="none" stroke="${c}" stroke-width="1.5" stroke-linecap="round" opacity="0.7"/>
        <path d="M80 20 Q90 10 95 20 Q90 30 80 20" fill="${c}" opacity="0.15" stroke="${c}" stroke-width="1"/>
        <line x1="10" y1="38" x2="100" y2="38" stroke="${c}" stroke-width="0.3" stroke-dasharray="2,3" opacity="0.3"/>
        <polyline points="10,38 30,34 50,36 70,30 90,32" fill="none" stroke="${c}" stroke-width="1" opacity="0.4"/>`; }
      break;
    case 'pbm': // light beam rays
      path = `<circle cx="55" cy="22" r="10" fill="${c}" opacity="0.15" stroke="${c}" stroke-width="1.2"/>
        ${[0,1,2,3,4,5].map(i => { const a=i*60*Math.PI/180; const x1=55+14*Math.cos(a); const y1=22+14*Math.sin(a); const x2=55+22*Math.cos(a); const y2=22+22*Math.sin(a); return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="${c}" stroke-width="1.5" stroke-linecap="round" opacity="0.5"/>`; }).join('')}`;
      break;
    case 'tps': case 'tus': // ultrasound pulses
      path = `<rect x="20" y="16" width="14" height="20" rx="3" fill="${c}" opacity="0.2" stroke="${c}" stroke-width="1"/>
        ${[0,1,2,3].map(i => `<path d="M38 26 Q${48+i*10} ${16-i*2} ${48+i*10} ${36+i*2}" fill="none" stroke="${c}" stroke-width="1.2" opacity="${0.6-i*0.12}"/>`).join('')}`;
      break;
    case 'pemf': // pulsed field rings
      path = `<ellipse cx="55" cy="25" rx="20" ry="12" fill="none" stroke="${c}" stroke-width="1.8" opacity="0.6"/>
        <ellipse cx="55" cy="25" rx="30" ry="8" fill="none" stroke="${c}" stroke-width="1" opacity="0.3"/>
        <ellipse cx="55" cy="25" rx="10" ry="5" fill="${c}" opacity="0.15"/>
        ${[22,37,55,73,88].map((x,i) => `<line x1="${x}" y1="42" x2="${x}" y2="${42-[6,12,16,10,5][i]}" stroke="${c}" stroke-width="1.5" stroke-linecap="round" opacity="0.5"/>`).join('')}`;
      break;
    case 'dbs': // deep electrode probe
      path = `<line x1="55" y1="6" x2="55" y2="38" stroke="${c}" stroke-width="2" opacity="0.7"/>
        ${[0,1,2,3].map(i => `<rect x="50" y="${26-i*6}" width="10" height="4" rx="1" fill="${c}" opacity="${0.7-i*0.1}"/>`).join('')}
        <circle cx="55" cy="40" r="3" fill="${c}" opacity="0.3"/>
        ${[0,1,2].map(i => `<circle cx="55" cy="40" r="${6+i*4}" fill="none" stroke="${c}" stroke-width="0.7" opacity="${0.25-i*0.06}"/>`).join('')}`;
      break;
    case 'vns': // vagus nerve
      path = `<path d="M55 6 Q50 14 52 22 Q54 30 50 38 Q48 44 52 48" fill="none" stroke="${c}" stroke-width="2" opacity="0.6"/>
        <circle cx="52" cy="22" r="4" fill="${c}" opacity="0.3"/>
        ${[0,1,2].map(i => `<circle cx="52" cy="22" r="${7+i*4}" fill="none" stroke="${c}" stroke-width="0.8" opacity="${0.3-i*0.08}"/>`).join('')}
        <rect x="72" y="18" width="20" height="12" rx="3" fill="${c}" opacity="0.12" stroke="${c}" stroke-width="1"/>
        <line x1="62" y1="22" x2="72" y2="24" stroke="${c}" stroke-width="1" stroke-dasharray="2,2" opacity="0.5"/>`;
      break;
    default: // generic signal
      { const pts = []; for (let i=0;i<=40;i++){const t=i/40; const x=10+t*90; const y=25-Math.sin(t*3*Math.PI)*12; pts.push(`${x.toFixed(1)},${y.toFixed(1)}`);} 
        path = `<polyline points="${pts.join(' ')}" fill="none" stroke="${c}" stroke-width="1.5" stroke-linecap="round" opacity="0.6"/>
        <line x1="10" y1="25" x2="100" y2="25" stroke="${c}" stroke-width="0.3" stroke-dasharray="2,3" opacity="0.3"/>`; }
  }
  return `<svg viewBox="0 0 ${w} ${h}" width="${w}" height="${h}" style="display:block">
    <defs><linearGradient id="dg-${deviceId}" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="${c}" stop-opacity="0.08"/>
      <stop offset="100%" stop-color="${c}" stop-opacity="0"/>
    </linearGradient></defs>
    <rect width="${w}" height="${h}" fill="url(#dg-${deviceId})" rx="6"/>
    ${path}
  </svg>`;
}

function _findProtoDevice(deviceItem) {
  const did = (deviceItem.id || '').toLowerCase();
  const dmod = (deviceItem.modality || deviceItem.name || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
  return PROTO_DEVICES.find(p => p.id === did || p.id === dmod) || null;
}

function _openDeviceModal(device, evStats, protoDevice) {
  const old = document.getElementById('ds-device-modal');
  if (old) old.remove();

  const c = _DEV_COLORS[protoDevice?.id] || _DEV_COLORS[(device.modality||'').toLowerCase()] || '#64748b';
  const de = evStats || {};
  const subtypes = protoDevice?.subtypes || [];
  const cat = protoDevice?.category || '';
  const icon = protoDevice?.icon || '';

  // Get protocols for this device
  const protos = PROTOCOL_LIBRARY.filter(p => {
    if (protoDevice) return p.device === protoDevice.id;
    const dn = (device.name || device.modality || '').toLowerCase();
    return (p.device || '').toLowerCase() === dn;
  });

  // Unique conditions from protocols
  const condSet = new Set(protos.map(p => p.conditionId));
  const conditions = [...condSet].map(cid => {
    const ce = getConditionEvidence(cid);
    return { id: cid, label: cid.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase()), papers: ce?.paperCount || 0 };
  }).sort((a,b) => b.papers - a.papers);

  const isCertified = device.regulatory_status && (
    device.regulatory_status.toLowerCase().includes('fda') ||
    device.regulatory_status.toLowerCase().includes('approved') ||
    device.regulatory_status.toLowerCase().includes('cleared')
  );

  const overlay = document.createElement('div');
  overlay.id = 'ds-device-modal';
  overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.55);display:flex;align-items:center;justify-content:center;padding:24px;backdrop-filter:blur(4px)';

  overlay.innerHTML = `
    <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg,12px);max-width:820px;width:100%;max-height:90vh;overflow-y:auto;box-shadow:0 24px 80px rgba(0,0,0,0.4)" onclick="event.stopPropagation()">
      <!-- Header -->
      <div style="position:sticky;top:0;z-index:1;background:var(--bg-card);border-bottom:1px solid var(--border);padding:20px 24px;display:flex;align-items:center;gap:16px">
        <div style="width:52px;height:52px;border-radius:12px;background:${c}14;border:1px solid ${c}30;display:flex;align-items:center;justify-content:center;font-size:24px;flex-shrink:0">${icon}</div>
        <div style="flex:1;min-width:0">
          <div style="font-family:var(--font-display);font-size:17px;font-weight:700;color:var(--text-primary)">${device.name || device.modality || '—'}</div>
          <div style="display:flex;gap:6px;align-items:center;margin-top:4px;flex-wrap:wrap">
            ${cat ? `<span style="font-size:10px;padding:2px 8px;border-radius:999px;background:${c}18;color:${c};font-weight:600">${cat}</span>` : ''}
            ${isCertified ? '<span style="font-size:10px;padding:2px 8px;border-radius:999px;background:rgba(74,222,128,0.12);color:var(--green);font-weight:600">FDA Certified</span>' : ''}
            ${device.manufacturer ? `<span style="font-size:10.5px;color:var(--text-tertiary)">${device.manufacturer}</span>` : ''}
          </div>
        </div>
        <button onclick="document.getElementById('ds-device-modal')?.remove();document.body.style.overflow=''" style="background:none;border:none;color:var(--text-tertiary);cursor:pointer;font-size:20px;padding:4px 8px">&times;</button>
      </div>

      <div style="padding:24px">
        <!-- Visualization + Quick Stats -->
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:24px">
          <div style="border-radius:12px;background:${c}08;border:1px solid ${c}18;padding:16px;text-align:center">
            <div style="transform:scale(1.6);transform-origin:center;margin:12px 0">${_miniDeviceSvg(protoDevice?.id || (device.modality||'').toLowerCase().replace(/\s+/g,'-').replace(/[^a-z0-9-]/g,''))}</div>
            <div style="font-size:11px;color:${c};font-weight:600;margin-top:12px">${protoDevice?.label || device.modality || 'Device'}</div>
          </div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;align-content:start">
            <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:10px;padding:12px;text-align:center">
              <div style="font-size:22px;font-weight:800;color:var(--teal)">${de.protocols || 0}</div>
              <div style="font-size:9.5px;color:var(--text-tertiary)">Protocols</div>
            </div>
            <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:10px;padding:12px;text-align:center">
              <div style="font-size:22px;font-weight:800;color:var(--blue)">${de.conditions || conditions.length}</div>
              <div style="font-size:9.5px;color:var(--text-tertiary)">Conditions</div>
            </div>
            <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:10px;padding:12px;text-align:center">
              <div style="font-size:22px;font-weight:800;color:var(--violet)">${de.papers ? de.papers.toLocaleString() : '—'}</div>
              <div style="font-size:9.5px;color:var(--text-tertiary)">Papers</div>
            </div>
            <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:10px;padding:12px;text-align:center">
              <div style="font-size:22px;font-weight:800;color:var(--green)">${de.gradeA || 0}</div>
              <div style="font-size:9.5px;color:var(--text-tertiary)">Grade A</div>
            </div>
          </div>
        </div>

        <!-- Description -->
        ${device.summary ? `<div style="margin-bottom:20px">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--text-tertiary);font-weight:600;margin-bottom:8px">Description</div>
          <div style="font-size:12.5px;color:var(--text-secondary);line-height:1.6">${device.summary}</div>
        </div>` : ''}

        <!-- Subtypes -->
        ${subtypes.length ? `<div style="margin-bottom:20px">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--text-tertiary);font-weight:600;margin-bottom:8px">Subtypes / Variants</div>
          <div style="display:flex;flex-wrap:wrap;gap:6px">
            ${subtypes.map(s => `<span style="font-size:11px;padding:4px 10px;border-radius:999px;background:${c}10;border:1px solid ${c}25;color:${c}">${s}</span>`).join('')}
          </div>
        </div>` : ''}

        <!-- Specifications -->
        ${(device.max_intensity_ma != null || device.frequency_hz_range || device.pulse_width_us || device.channels) ? `<div style="margin-bottom:20px">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--text-tertiary);font-weight:600;margin-bottom:8px">Technical Specifications</div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">
            ${device.max_intensity_ma != null ? `<div style="background:rgba(255,255,255,0.02);border:1px solid var(--border);border-radius:8px;padding:10px 12px">
              <div style="font-size:9.5px;color:var(--text-tertiary)">Max Intensity</div>
              <div style="font-size:14px;font-weight:700;color:var(--text-primary);font-family:var(--font-mono)">${device.max_intensity_ma} mA</div>
            </div>` : ''}
            ${device.frequency_hz_range ? `<div style="background:rgba(255,255,255,0.02);border:1px solid var(--border);border-radius:8px;padding:10px 12px">
              <div style="font-size:9.5px;color:var(--text-tertiary)">Frequency Range</div>
              <div style="font-size:14px;font-weight:700;color:var(--text-primary);font-family:var(--font-mono)">${device.frequency_hz_range} Hz</div>
            </div>` : ''}
            ${device.pulse_width_us != null ? `<div style="background:rgba(255,255,255,0.02);border:1px solid var(--border);border-radius:8px;padding:10px 12px">
              <div style="font-size:9.5px;color:var(--text-tertiary)">Pulse Width</div>
              <div style="font-size:14px;font-weight:700;color:var(--text-primary);font-family:var(--font-mono)">${device.pulse_width_us} µs</div>
            </div>` : ''}
            ${device.channels ? `<div style="background:rgba(255,255,255,0.02);border:1px solid var(--border);border-radius:8px;padding:10px 12px">
              <div style="font-size:9.5px;color:var(--text-tertiary)">Channels</div>
              <div style="font-size:14px;font-weight:700;color:var(--text-primary);font-family:var(--font-mono)">${device.channels}</div>
            </div>` : ''}
          </div>
        </div>` : ''}

        <!-- Protocols -->
        ${protos.length ? `<div style="margin-bottom:20px">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--text-tertiary);font-weight:600;margin-bottom:8px">Evidence-Based Protocols (${protos.length})</div>
          <div style="display:flex;flex-direction:column;gap:6px;max-height:260px;overflow-y:auto">
            ${protos.slice(0, 15).map(p => {
              const gradeColor = {'A':'var(--green)','B':'var(--blue)','C':'var(--amber)','D':'var(--rose)'}[p.evidenceGrade] || 'var(--text-tertiary)';
              return `<div style="display:flex;align-items:center;gap:10px;padding:8px 12px;border-radius:8px;background:rgba(255,255,255,0.02);border:1px solid var(--border)">
                <span style="font-size:10px;font-weight:700;padding:2px 6px;border-radius:4px;background:${gradeColor}18;color:${gradeColor}">${p.evidenceGrade || '?'}</span>
                <div style="flex:1;min-width:0">
                  <div style="font-size:11.5px;font-weight:600;color:var(--text-primary);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${p.name}</div>
                  <div style="font-size:10px;color:var(--text-tertiary)">${p.target || ''}</div>
                </div>
                <div style="font-size:10px;color:var(--text-tertiary);white-space:nowrap">${p.subtype || ''}</div>
              </div>`;
            }).join('')}
            ${protos.length > 15 ? `<div style="text-align:center;font-size:10.5px;color:var(--text-tertiary);padding:6px">+${protos.length-15} more protocols</div>` : ''}
          </div>
        </div>` : ''}

        <!-- Conditions -->
        ${conditions.length ? `<div style="margin-bottom:20px">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--text-tertiary);font-weight:600;margin-bottom:8px">Treated Conditions (${conditions.length})</div>
          <div style="display:flex;flex-wrap:wrap;gap:6px">
            ${conditions.map(cd => `<span style="font-size:10.5px;padding:4px 10px;border-radius:999px;background:rgba(255,255,255,0.04);border:1px solid var(--border);color:var(--text-secondary)">${cd.label}${cd.papers ? ` <span style="color:var(--text-tertiary);font-size:9px">(${cd.papers.toLocaleString()})</span>` : ''}</span>`).join('')}
          </div>
        </div>` : ''}

        <!-- Regulatory -->
        ${device.regulatory_status ? `<div style="margin-bottom:12px">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--text-tertiary);font-weight:600;margin-bottom:6px">Regulatory Status</div>
          <div style="font-size:12px;color:var(--text-secondary)">${device.regulatory_status}</div>
        </div>` : ''}
      </div>
    </div>`;

  overlay.addEventListener('click', (e) => { if (e.target === overlay) { overlay.remove(); document.body.style.overflow = ''; } });
  document.body.style.overflow = 'hidden';
  document.body.appendChild(overlay);
  const esc = (e) => { if (e.key === 'Escape') { overlay.remove(); document.body.style.overflow = ''; document.removeEventListener('keydown', esc); } };
  document.addEventListener('keydown', esc);
}

function renderDeviceGrid(items, evStats) {
  const _ev = evStats || {};
  return `<div class="g3">
    ${items.map((d, idx) => {
      const isCertified = d.regulatory_status && (
        d.regulatory_status.toLowerCase().includes('fda') ||
        d.regulatory_status.toLowerCase().includes('ce mark') ||
        d.regulatory_status.toLowerCase().includes('approved') ||
        d.regulatory_status.toLowerCase().includes('cleared')
      );
      const _did = (d.id || '').toLowerCase();
      const _dmod = (d.modality || d.name || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
      const _de = _ev[_did] || _ev[_dmod] || {};
      const protoDevice = _findProtoDevice(d);
      const devColor = _DEV_COLORS[protoDevice?.id] || _DEV_COLORS[_dmod] || '#64748b';
      const svgId = protoDevice?.id || _dmod;

      return `<div class="card" style="margin-bottom:0;cursor:pointer;transition:border-color var(--transition),transform .15s,box-shadow .15s"
        onmouseover="this.style.borderColor='${devColor}60';this.style.transform='translateY(-2px)';this.style.boxShadow='0 8px 24px ${devColor}15'"
        onmouseout="this.style.borderColor='var(--border)';this.style.transform='';this.style.boxShadow=''"
        onclick="window._openDeviceDetail(${idx})">
        <div style="padding:14px 16px">
          <div style="display:flex;gap:14px;align-items:flex-start">
            <!-- Mini Device SVG -->
            <div style="flex-shrink:0;width:120px;border-radius:10px;background:${devColor}08;border:1px solid ${devColor}18;padding:8px 5px 6px;text-align:center">
              ${_miniDeviceSvg(svgId)}
              <div style="font-size:9px;color:${devColor};font-weight:600;margin-top:3px">${protoDevice?.category || d.modality || ''}</div>
            </div>
            <!-- Content -->
            <div style="min-width:0;flex:1">
              <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin-bottom:4px">
                <span style="font-size:10px;padding:2px 7px;border-radius:999px;background:${devColor}15;color:${devColor};font-weight:600">${d.modality || '—'}</span>
                ${isCertified ? '<span style="font-size:9px;font-weight:700;padding:2px 6px;border-radius:3px;background:rgba(74,222,128,0.12);color:var(--green)">FDA</span>' : ''}
              </div>
              <div style="font-family:var(--font-display);font-size:13px;font-weight:600;color:var(--text-primary);margin-bottom:2px">${d.name || '—'}</div>
              ${d.manufacturer ? `<div style="font-size:10.5px;color:var(--text-tertiary);margin-bottom:6px">${d.manufacturer}</div>` : ''}
              <div style="font-size:11px;color:var(--text-secondary);line-height:1.5;margin-bottom:8px">${(d.summary || '').slice(0, 90)}${(d.summary || '').length > 90 ? '...' : ''}</div>
              ${(_de.protocols || _de.papers) ? `<div style="display:flex;gap:8px;flex-wrap:wrap;font-size:10px">
                ${_de.protocols ? `<span style="color:var(--teal);font-weight:600">${_de.protocols} protocols</span>` : ''}
                ${_de.papers ? `<span style="color:var(--violet);font-weight:600">${_de.papers.toLocaleString()} papers</span>` : ''}
                ${_de.gradeA ? `<span style="color:var(--green);font-weight:600">${_de.gradeA} Grade A</span>` : ''}
              </div>` : ''}
            </div>
            <!-- Arrow -->
            <div style="color:${devColor};opacity:0.4;font-size:18px;padding-top:14px">&rarr;</div>
          </div>
        </div>
      </div>`;
    }).join('')}
  </div>`;
}

// ── Brain Regions ─────────────────────────────────────────────────────────────
export async function pgBrainRegions(setTopbar) {
  setTopbar('Brain Regions', `<button class="btn btn-ghost btn-sm">Export</button>`);
  const el = document.getElementById('content');
  el.innerHTML = spinner();

  let items = [];
  try {
    const res = await api.listBrainRegions();
    items = res?.items || [];
  } catch (e) {
    el.innerHTML = `<div class="notice notice-warn">Could not load brain regions: ${e.message}</div>`;
    return;
  }

  el.innerHTML = `
  <div style="display:flex;gap:8px;margin-bottom:16px">
    <input class="form-control" id="br-search" placeholder="Search regions, functions, conditions…" style="flex:1" oninput="window.filterBrainRegions()">
    <select class="form-control" id="br-lobe" style="width:auto" onchange="window.filterBrainRegions()">
      <option value="">All Lobes</option>
      <option>Frontal</option><option>Parietal</option><option>Temporal</option><option>Occipital</option><option>Subcortical</option>
    </select>
  </div>
  <div id="br-body">
    ${items.length === 0
      ? emptyState('◎', 'No brain region data loaded.')
      : renderBrainRegionTable(items)}
  </div>`;

  window._brainRegionsData = items;

  window.filterBrainRegions = function() {
    const q = document.getElementById('br-search').value.toLowerCase();
    const lobe = document.getElementById('br-lobe').value.toLowerCase();
    const filtered = (window._brainRegionsData || []).filter(r => {
      const matchQ = !q || (r.name || '').toLowerCase().includes(q) || (r.primary_functions || []).join(' ').toLowerCase().includes(q);
      const matchL = !lobe || (r.lobe || '').toLowerCase().includes(lobe);
      return matchQ && matchL;
    });
    const body = document.getElementById('br-body');
    if (body) body.innerHTML = filtered.length === 0 ? emptyState('◎', 'No regions match filter.') : renderBrainRegionTable(filtered);
  };
}

function renderBrainRegionTable(items) {
  return cardWrap(`Brain Regions (${items.length})`, `<div style="overflow-x:auto">
    <table class="ds-table">
      <thead><tr>
        <th>Region</th><th>Lobe</th><th>EEG Position</th><th>Primary Functions</th><th>Key Conditions</th><th>Targetable</th>
      </tr></thead>
      <tbody>
        ${items.map(r => `<tr>
          <td>
            <div style="font-weight:500">${r.name || '—'}</div>
            ${r.abbreviation ? `<div style="font-size:10.5px;color:var(--teal);font-family:var(--font-mono)">${r.abbreviation}</div>` : ''}
          </td>
          <td style="color:var(--text-secondary)">${r.lobe || '—'}</td>
          <td class="mono" style="color:var(--blue)">${r.eeg_position_10_20 || '—'}</td>
          <td style="font-size:11.5px;color:var(--text-secondary)">${(r.primary_functions || []).slice(0, 2).join(', ') || '—'}</td>
          <td style="font-size:11.5px">${(r.key_conditions || []).slice(0, 2).map(c => tag(c)).join('')}</td>
          <td>${(r.targetable_modalities || []).slice(0, 3).map(m => `<span class="tag" style="color:var(--teal)">${m}</span>`).join('')}</td>
        </tr>`).join('')}
      </tbody>
    </table>
  </div>`);
}

